151→// Unified error type for pablo-core operations.
152→[Error]
153→interface PabloError {
154→    AudioPreprocessing(string message);
155→    WhisperInit(string message);
156→    WhisperTranscribe(string message);
157→    ApiClient(u16 status_code, string message);
158→    JsonParse(string message);
159→    Unauthenticated();
160→    Forbidden();
161→    NotFound(string resource);
162→    ConflictState(string message);
163→};
