165→// Options for rendering to Google Meet format.
166→dictionary GoogleMeetOptions {
167→    string session_date;
168→    string therapist_name;
169→    string client_name;
170→    string client_a_name;
171→    string client_b_name;
172→};
173→
174→// Configuration for a local transcription run.
175→dictionary TranscriptionConfig {
176→    string model_path;
177→    u8 mic_channels;
178→    u32 mic_sample_rate;
179→    u8 system_channels;
180→    u32 system_sample_rate;
181→};
182→
183→// A raw ASR segment from Whisper. Timestamps are milliseconds.
184→dictionary RawSegment {
185→    i64 start_ms;
186→    i64 end_ms;
187→    string text;
188→};
189→
190→// Who spoke this segment.
191→enum SpeakerLabel {
192→    "Therapist",
193→    "Client",
194→    "ClientA",
195→    "ClientB",
196→    "Unknown",
197→};
198→
199→// Whether the session has one or two clients.
200→enum SessionMode {
201→    "OneToOne",
202→    "Couples",
203→};
204→
205→// A single speaker turn with start/end timestamps (seconds) and transcript text.
206→dictionary TranscriptSegment {
207→    SpeakerLabel speaker;
208→    double start_seconds;
209→    double end_seconds;
210→    string text;
211→};
212→
213→// The full transcript for one session.
214→dictionary TranscriptResult {
215→    string session_id;
216→    SessionMode session_mode;
217→    sequence<TranscriptSegment> segments;
218→};
219→
220→// ── Domain types for Pablo API client ────────────────────────────────────────
221→
222→enum SessionStatus {
223→    "Scheduled",
224→    "InProgress",
225→    "RecordingComplete",
226→    "Queued",
227→    "Processing",
228→    "PendingReview",
229→    "Finalized",
230→    "Cancelled",
231→    "Failed",
232→};
233→
234→enum VideoPlatform {
235→    "Zoom",
236→    "Teams",
237→    "Meet",
238→    "None",
239→};
240→
241→enum SessionType {
242→    "Individual",
243→    "Couples",
244→};
245→
246→enum SessionSource {
247→    "Web",
248→    "Companion",
249→    "Calendar",
250→};
251→
252→enum QualityPreset {
253→    "Fast",
254→    "Balanced",
255→    "Accurate",
256→};
257→
258→// Minimal patient info embedded in a session.
259→dictionary PatientSummary {
260→    string id;
261→    string first_name;
262→    string last_name;
263→};
264→
265→// A therapy session.
266→dictionary Session {
267→    string id;
268→    string patient_id;
269→    PatientSummary? patient;
270→    SessionStatus status;
271→    string? scheduled_at;
272→    string? started_at;
273→    string? ended_at;
274→    u32 duration_minutes;
275→    string? video_link;
276→    VideoPlatform? video_platform;
277→    SessionType session_type;
278→    SessionSource source;
279→    string? notes;
280→    string created_at;
281→    string updated_at;
282→};
283→
284→// Request body for creating a new session.
285→dictionary CreateSessionRequest {
286→    string patient_id;
287→    string scheduled_at;
288→    u32? duration_minutes;
289→    string? video_link;
290→    VideoPlatform? video_platform;
291→    SessionType? session_type;
292→    SessionSource? source;
293→    string? notes;
294→};
295→
296→// Request body for updating an existing session.
297→dictionary UpdateSessionRequest {
298→    string? scheduled_at;
299→    string? video_link;
300→    VideoPlatform? video_platform;
301→    u32? duration_minutes;
302→    string? notes;
303→};
304→
305→// Therapist preference settings.
306→dictionary UserPreferences {
307→    VideoPlatform default_video_platform;
308→    SessionType default_session_type;
309→    u32 default_duration_minutes;
310→    boolean auto_transcribe;
311→    QualityPreset quality_preset;
312→    string therapist_display_name;
313→};
314→
315→// User profile from the Pablo backend.
316→dictionary UserProfile {
317→    string id;
318→    string email;
319→    string first_name;
320→    string last_name;
321→    string role;
322→    string created_at;
323→};
324→
325→// BAA acceptance status.
326→dictionary BaaStatus {
327→    boolean baa_accepted;
328→    string? accepted_at;
329→};
330→
331→// A patient record.
332→dictionary Patient {
333→    string id;
334→    string user_id;
335→    string first_name;
336→    string last_name;
337→    string? email;
338→    string? phone;
339→    string status;
340→    string? date_of_birth;
341→    string? diagnosis;
342→    u32 session_count;
343→    string? last_session_date;
344→    string? next_session_date;
345→    string created_at;
346→    string updated_at;
347→};
348→
349→// Request body for creating a new patient.
350→dictionary CreatePatientRequest {
351→    string first_name;
352→    string last_name;
353→    string? email;
354→    string? phone;
355→    string? date_of_birth;
356→    string? diagnosis;
357→};
358→
359→// Paginated list of sessions.
360→dictionary SessionListResponse {
361→    sequence<Session> data;
362→    u32 total;
363→    u32 page;
364→    u32 page_size;
365→    boolean has_more;
366→};
367→
368→// Paginated list of patients.
369→dictionary PatientListResponse {
370→    sequence<Patient> data;
371→    u32 total;
372→    u32 page;
373→    u32 page_size;
374→    boolean has_more;
375→};
376→
377→// Response from uploading a transcript.
378→dictionary TranscriptUploadResponse {
379→    string id;
380→    SessionStatus status;
381→    string message;
382→};
383→
384→// Response from uploading a recording file.
385→dictionary UploadResponse {
386→    string id;
387→    string status;
388→};
