import Foundation
import os
import SwiftUI

/// Manages fetching and displaying the patient list from the backend.
@MainActor
@Observable
final class PatientViewModel {
    var patients: [Patient] = []
    var isLoading = false
    var errorMessage: String?
    var showError = false
    var searchText = ""

    var backendURL = "http://localhost:8000" {
        didSet {
            if URLValidator.validateScheme(backendURL) == nil {
                apiClient = APIClient(baseURL: backendURL)
            }
        }
    }

    private var apiClient: APIClient
    private let logger = Logger(subsystem: AppConstants.appBundleID, category: "PatientViewModel")

    init() {
        self.apiClient = APIClient()
    }

    /// Configures the API client with a token provider for authenticated requests.
    func configureAuth(getToken: @escaping @Sendable () async throws -> String) {
        apiClient = APIClient(baseURL: backendURL)
        apiClient.getToken = getToken
    }

    /// Debug status visible in the UI during development.
    var debugStatus = ""

    func loadPatients() async {
        guard apiClient.getToken != nil else {
            debugStatus = "Waiting for auth..."
            return
        }
        debugStatus = "Loading from \(apiClient.baseURL)..."
        isLoading = true
        defer { isLoading = false }

        do {
            let response = try await apiClient.fetchPatients(search: searchText)
            patients = response.data
            debugStatus = "Loaded \(response.data.count) of \(response.total) patients"
            logger.info("Loaded \(response.data.count) of \(response.total) patients")
        } catch {
            debugStatus = "Error: \(error.localizedDescription)"
            logger.error("Failed to load patients: \(error.localizedDescription)")
            errorMessage = "Failed to load patients: \(error.localizedDescription)"
            showError = true
        }
    }
}

import Foundation
import os

/// Thin wrapper around pablo-core Rust API client.
/// Centralizes base URL and auth token so ViewModels don't scatter them.
@MainActor
final class APIClient {
    private let logger = Logger(subsystem: AppConstants.appBundleID, category: "APIClient")

    nonisolated let baseURL: URL
    nonisolated private let baseURLString: String

    /// Optional closure to provide a Bearer token for authenticated requests.
    var getToken: (@Sendable () async throws -> String)?

    init(baseURL: String = "http://localhost:8000") {
        if let error = URLValidator.validateScheme(baseURL) {
            preconditionFailure("APIClient: \(error)")
        }
        guard let url = URL(string: baseURL) else {
            preconditionFailure("APIClient initialized with invalid base URL: \(baseURL)")
        }
        self.baseURL = url
        self.baseURLString = baseURL
    }

    // MARK: - Token helper

    private func requireToken() async throws -> String {
        guard let getToken else {
            throw APIError.notAuthenticated
        }
        return try await getToken()
    }

    // MARK: - Health

    /// Checks if the backend is reachable via the Rust API client.
    func healthCheck() async throws -> Bool {
        do {
            try await Pablo.healthCheck(baseUrl: baseURLString)
            return true
        } catch {
            logger.warning("Health check failed: \(error.localizedDescription)")
            return false
        }
    }

    // MARK: - Recordings

    /// Uploads a recording file to the backend via the Rust API client.
    func uploadRecording(
        fileURL: URL,
        onProgress: @Sendable @escaping (Double) -> Void
    ) async throws -> UploadResponse {
        let token = try await requireToken()
        logger.info("Uploading \(fileURL.lastPathComponent)")

        // Simulate incremental progress since the Rust client
        // doesn't provide upload progress callbacks.
        onProgress(0.3)

        let response = try await Pablo.uploadRecording(
            baseUrl: baseURLString,
            token: token,
            filePath: fileURL.path
        )

        onProgress(1.0)
        logger.info("Upload successful: \(response.id)")
        return response
    }

    // MARK: - Patients

    /// Fetches a paginated list of patients via the Rust API client.
    func fetchPatients(
        search: String = "",
        page: Int = 1,
        pageSize: Int = 50
    ) async throws -> PatientListResponse {
        let token = try await requireToken()

        let response = try await Pablo.fetchPatients(
            baseUrl: baseURLString,
            token: token,
            search: search.isEmpty ? nil : search,
            page: UInt32(page),
            pageSize: UInt32(pageSize)
        )

        logger.info("Fetched \(response.data.count) of \(response.total) patients")
        return response
    }

    /// Creates a new patient via the Rust API client.
    func createPatient(
        firstName: String,
        lastName: String,
        email: String? = nil,
        phone: String? = nil,
        dateOfBirth: String? = nil,
        diagnosis: String? = nil
    ) async throws -> Patient {
        let token = try await requireToken()

        let request = CreatePatientRequest(
            firstName: firstName,
            lastName: lastName,
            email: email,
            phone: phone,
            dateOfBirth: dateOfBirth,
            diagnosis: diagnosis
        )

        let patient = try await Pablo.createPatient(
            baseUrl: baseURLString,
            token: token,
            request: request
        )

        logger.info("Created patient: \(patient.id)")
        return patient
    }

    // MARK: - Sessions

    /// Fetches today's sessions for the given timezone via the Rust API client.
    func fetchTodaySessions(timezone: String) async throws -> [Session] {
        let token = try await requireToken()

        let sessions = try await Pablo.fetchTodaySessions(
            baseUrl: baseURLString,
            token: token,
            timezone: timezone
        )

